// 헬스체크 대상 모델 — 각 API에 ping 테스트
const CEREBRAS_KEY = $env('CEREBRAS_API_KEY');
const OR_KEY = $env('OPENROUTER_API_KEY');

return [
  {
    json: {
      name: 'cerebras',
      url: 'https://api.cerebras.ai/v1/chat/completions',
      model: 'llama3.1-8b',
      auth: `Bearer ${CEREBRAS_KEY}`,
      referer: ''
    }
  },
  {
    json: {
      name: 'or-gemini',
      url: 'https://openrouter.ai/api/v1/chat/completions',
      model: 'google/gemini-2.0-flash-lite-001',
      auth: `Bearer ${OR_KEY}`,
      referer: 'https://career-aptitude-final.web.app'
    }
  },
  {
    json: {
      name: 'or-step',
      url: 'https://openrouter.ai/api/v1/chat/completions',
      model: 'stepfun/step-3.5-flash',
      auth: `Bearer ${OR_KEY}`,
      referer: 'https://career-aptitude-final.web.app'
    }
  }
];

// 응답 분석: 200 + choices 있으면 alive
const results = [];

for (const item of $input.all()) {
  const name = item.json.name || 'unknown';
  const statusCode = item.json.$response?.statusCode ?? 0;
  const hasContent = !!(item.json.choices?.[0]?.message?.content);
  const alive = (statusCode >= 200 && statusCode < 300) && hasContent;
  results.push({ name, alive, statusCode });
}

// 폴백 모델 결정 로직
const dead = results.filter(r => !r.alive).map(r => r.name);
const config = {};

// cerebras 죽으면 or_model 우선 사용 (or_model 필드는 유지)
if (!dead.includes('cerebras')) {
  config.cerebras_model = 'llama3.1-8b';
} else {
  config.cerebras_model = dead.includes('or-gemini') ? 'stepfun/step-3.5-flash' : 'google/gemini-2.0-flash-lite-001';
  // cerebras가 죽으면 cerebras_model을 fallback용 OR 모델로 덮어씌워
  // 실제로는 getModelConfig()가 cerebras_model을 Cerebras API에만 쓰므로
  // or_model/or_model_2 만 변경하는 것으로 충분
  config.cerebras_model = 'llama3.1-8b'; // cerebras 자체 모델명은 고정
}

if (dead.includes('or-gemini') && !dead.includes('or-step')) {
  config.or_model = 'stepfun/step-3.5-flash';
} else if (!dead.includes('or-gemini')) {
  config.or_model = 'google/gemini-2.0-flash-lite-001';
} else {
  config.or_model = 'openrouter/auto'; // 둘 다 죽으면 auto
}

if (dead.includes('or-step')) {
  config.or_model_2 = 'openrouter/auto';
} else {
  config.or_model_2 = 'stepfun/step-3.5-flash';
}

return [{ json: { dead, config, needsUpdate: dead.length > 0, results } }];

const dead = $json.dead;
const config = $json.config;
console.log(`[AI Healthcheck] 모델 장애 감지: ${dead.join(', ')} → 폴백 적용:`, config);
return [{ json: { status: 'switched', dead, config } }];

